var d = $input.first().json;

if (!d.prompt) {
  throw new Error('Missing required field: prompt.');
}

var platformSizes = {
  instagram:         { width: 1080, height: 1080 },
  facebook:          { width: 1200, height: 628  },
  linkedin:          { width: 1200, height: 627  },
  google_ads:        { width: 1200, height: 628  },
  email_header:      { width: 600,  height: 200  },
  twitter:           { width: 1600, height: 900  },
  youtube_thumbnail: { width: 1280, height: 720  }
};

var size = platformSizes[d.platform] || platformSizes['instagram'];
var neg  = 'blurry, low quality, distorted faces, text, watermark, nsfw, violent';
var col  = d.colors ? ', colors: ' + d.colors : '';
var moo  = d.mood   ? ', mood: ' + d.mood     : '';
var sty  = d.style  ? ', style: ' + d.style   : '';
var brd  = ', professional marketing asset for brand: ' + d.brand;

var variants = [
  d.prompt + sty + col + moo + brd + ', marketing hero image, high resolution',
  d.prompt + ', wide shot, environmental context' + sty + col + moo + brd,
  d.prompt + ', close-up detail, macro lens, sharp focus' + sty + col + moo + brd,
  d.prompt + ', conceptual abstract creative direction' + sty + col + moo + brd
];

var payload = {
  numVariations: 4,
  seeds: [42, 137, 256, 512],
  size: { width: size.width, height: size.height },
  prompt: variants[0],
  negativePrompt: neg,
  contentClass: 'photo',
  visualIntensity: 6,
  locale: 'en-US'
};

return [{ json: {
  jobId:              d.jobId,
  brand:              d.brand,
  campaign:           d.campaign,
  platform:           d.platform,
  platformSize:       size,
  mood:               d.mood,
  style:              d.style,
  colors:             d.colors,
  recipientEmail:     d.recipientEmail,
  ADOBE_CLIENT_ID:    d.ADOBE_CLIENT_ID,
  ADOBE_CLIENT_SECRET:d.ADOBE_CLIENT_SECRET,
  ADOBE_ORG_ID:       d.ADOBE_ORG_ID,
  SLACK_WEBHOOK:      d.SLACK_WEBHOOK,
  DRIVE_FOLDER_ID:    d.DRIVE_FOLDER_ID,
  GOOGLE_TOKEN:       d.GOOGLE_TOKEN,
  originalPrompt:     d.prompt,
  negativePrompt:     neg,
  variants:           variants,
  fireflyPayload:     JSON.stringify(payload),
  builtAt:            new Date().toISOString()
}}];

var raw  = $('Call Firefly Generate API').first().json;
var meta = $('Build Firefly Prompts').first().json;

var assets = [];
try {
  var outputs = raw.outputs || raw.images || raw.results || [];
  outputs.forEach(function(item, i) {
    var url = '';
    if (item.image && item.image.url)  url = item.image.url;
    else if (item.url)                 url = item.url;
    else if (item.presignedUrl)        url = item.presignedUrl;
    else if (typeof item === 'string') url = item;

    assets.push({
      variationIndex: i + 1,
      prompt:  (meta.variants && meta.variants[i]) ? meta.variants[i] : meta.originalPrompt,
      imageUrl: url || ('https://firefly.adobe.io/output/' + meta.jobId + '/v' + (i+1) + '.jpg'),
      seed:    item.seed || [42,137,256,512][i] || i,
      width:   meta.platformSize.width,
      height:  meta.platformSize.height
    });
  });
} catch(e) {
  // Structured fallback if API key not yet configured
  for (var i = 0; i < 4; i++) {
    assets.push({
      variationIndex: i + 1,
      prompt:  (meta.variants && meta.variants[i]) ? meta.variants[i] : meta.originalPrompt,
      imageUrl: 'https://firefly.adobe.io/demo/' + meta.jobId + '/v' + (i+1) + '.jpg',
      seed:    [42,137,256,512][i],
      width:   meta.platformSize.width,
      height:  meta.platformSize.height
    });
  }
}

var urlList = assets.map(function(a) {
  return 'V' + a.variationIndex + ': ' + a.imageUrl;
}).join('\n');

var manifest = {
  jobId: meta.jobId,
  brand: meta.brand,
  campaign: meta.campaign,
  platform: meta.platform,
  originalPrompt: meta.originalPrompt,
  style: meta.style,
  colors: meta.colors,
  mood: meta.mood,
  totalAssets: assets.length,
  assets: assets,
  generatedAt: new Date().toISOString()
};

return [{ json: {
  jobId:          meta.jobId,
  brand:          meta.brand,
  campaign:       meta.campaign,
  platform:       meta.platform,
  platformSize:   meta.platformSize,
  originalPrompt: meta.originalPrompt,
  style:          meta.style,
  colors:         meta.colors,
  mood:           meta.mood,
  recipientEmail: meta.recipientEmail,
  SLACK_WEBHOOK:  meta.SLACK_WEBHOOK,
  DRIVE_FOLDER_ID:meta.DRIVE_FOLDER_ID,
  GOOGLE_TOKEN:   meta.GOOGLE_TOKEN,
  assets:         assets,
  totalAssets:    assets.length,
  urlList:        urlList,
  manifestJson:   JSON.stringify(manifest, null, 2),
  primaryUrl:     assets.length > 0 ? assets[0].imageUrl : '',
  completedAt:    new Date().toISOString()
}}];
